package com.chaobo.scm.supplier.application.quality;import com.chaobo.scm.common.api.PageResult;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.quality.*;import com.chaobo.scm.supplier.domain.shared.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.*;import java.util.*;import java.util.function.*;
@Service public class SupplierQualityIssueApplicationService {private final SupplierQualityIssueRepository repo;private final SupplierQualityIssueReadModelPort read;private final OutboxRepository outbox;private final AuditLogRepository audit;private final IdentifierGenerator ids;private final TransactionalCommandExecutor executor;public SupplierQualityIssueApplicationService(SupplierQualityIssueRepository repo,SupplierQualityIssueReadModelPort read,OutboxRepository outbox,AuditLogRepository audit,IdentifierGenerator ids,TransactionalCommandExecutor executor){this.repo=repo;this.read=read;this.outbox=outbox;this.audit=audit;this.ids=ids;this.executor=executor;}@Transactional(readOnly=true)public PageResult<SupplierQualityIssueView> page(Long supplierId,Long scope,Integer status,Integer severity,int page,int size){if(page<1||size<1||size>100)throw new BusinessException(ErrorCode.VALIDATION_FAILED,"分页参数不合法");return read.page(scope==null?supplierId:scope,status,severity,page,size);}@Transactional(readOnly=true)public SupplierQualityIssueView detail(long id,Long scope){var v=read.detail(id).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"质量问题不存在"));if(scope!=null&&scope!=v.supplierId())throw new BusinessException(ErrorCode.NOT_FOUND,"质量问题不存在");return v;}@Transactional public CommandResult create(long supplierId,String sourceType,String sourceNo,String issueType,int severity,String description,CommandContext c){c.requirePermission("supplier:quality:create");c.requireSupplierScope(supplierId);return executor.execute("supplier:quality",c,new Create(supplierId,sourceType,sourceNo,issueType,severity,description),()->persist(SupplierQualityIssueAggregate.create(supplierId,sourceType,sourceNo,issueType,severity,description,c.operatorId(),ids),c,"CREATE_QUALITY_ISSUE",null));}@Transactional public CommandResult requestRectification(long id,int version,OffsetDateTime deadline,CommandContext c){c.requirePermission("supplier:quality:rectify");return change(id,version,"REQUEST_RECTIFICATION",c,a->a.requestRectification(deadline,c.operatorId(),ids));}@Transactional public CommandResult submitPlan(long id,int version,String plan,CommandContext c){c.requirePermission("supplier:quality:submit_plan");return change(id,version,"SUBMIT_RECTIFICATION",c,a->a.submitPlan(plan,c.operatorId(),ids));}@Transactional public CommandResult verify(long id,int version,boolean passed,String comment,CommandContext c){c.requirePermission("supplier:quality:verify");return change(id,version,"VERIFY_RECTIFICATION",c,a->a.verify(passed,comment,c.operatorId(),ids));}@Transactional public void markOverdue(){for(long id:read.overdueIds()){var a=repo.findById(id).orElse(null);if(a==null)continue;String before=snapshot(a);a.markOverdue(0,ids);if(a.status()==QualityIssueStatus.OVERDUE){var c=new CommandContext(0,"系统",0,null,"quality-overdue-"+id,null,"quality-overdue-"+id,Set.of());persist(a,c,"MARK_RECTIFICATION_OVERDUE",before);}}}private CommandResult change(long id,int version,String op,CommandContext c,Consumer<SupplierQualityIssueAggregate> action){return executor.execute("supplier:quality",c,new Change(id,version,op),()->{var a=repo.findById(id).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"质量问题不存在"));c.requireSupplierScope(a.supplierId());if(a.version()!=version)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"质量问题已被更新");String before=snapshot(a);action.accept(a);return persist(a,c,op,before);});}private CommandResult persist(SupplierQualityIssueAggregate a,CommandContext c,String op,String before){repo.save(a,c.operatorId());var events=a.pullEvents();outbox.saveAll(events);audit.save(c,op,"SUPPLIER_QUALITY_ISSUE",a.id(),a.no(),before,snapshot(a));return new CommandResult(a.id(),a.no(),a.status().code(),a.status().label(),a.version(),events.isEmpty()?null:events.getLast().eventCode(),false);}private String snapshot(SupplierQualityIssueAggregate a){return "{\"issueNo\":\"%s\",\"status\":%d,\"version\":%d}".formatted(a.no(),a.status().code(),a.version());}private record Create(long supplierId,String sourceType,String sourceNo,String issueType,int severity,String description){}private record Change(long id,int version,String operation){}
}
